211	                    bbs[fl].max_r = std::max(bbs[fl].max_r, r);
212	                    bbs[fl].min_c = std::min(bbs[fl].min_c, c);
213	                    bbs[fl].max_c = std::max(bbs[fl].max_c, c);
214	                    bbs[fl].count++;
