220	        for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
221	            if (bbs[fl].count == 0) continue;
222	            int bb_area = (bbs[fl].max_r - bbs[fl].min_r + 1) * (bbs[fl].max_c - bbs[fl].min_c + 1);
223	            // Negative penalty: larger bb_area relative to count is bad
224	            // We want count / bb_area to be high (close to 1)
225	            // Penalty = bb_area - count (lower is better, so negate)
226	            score -= (double)(bb_area - bbs[fl].count) * bbs[fl].count;
227	        }
