255	        int adj_count = count_same_flavor_adjacencies();
256	        double bb_tight = bounding_box_tightness();
257	        double rc_purity = row_col_purity();
258	
259	        double progress = static_cast<double>(turn_num_1_indexed) / NUM_TURNS;
260	
261	        // Connectivity: the actual objective, increasingly important
262	        double conn_weight = 25.0 + 75.0 * progress;
263	        // Adjacency: local proxy
264	        double adj_weight = 35.0;
265	        // Bounding box tightness: encourages compaction into small rectangles
266	        double bb_weight = 3.0 * (1.0 - progress * 0.3);
267	        // Row/column purity: encourages band-like flavor separation
268	        double rc_weight = 2.0 * (1.0 - progress * 0.5);
269	
270	        return conn_weight * sum_sq_comp + adj_weight * adj_count
271	             + bb_weight * bb_tight + rc_weight * rc_purity;
272	    }
