301	double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed,
302	                      int depth_remaining, int samples_d1, int samples_d2) {
303	    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
304	        return state_after_tilt.evaluate();
305	    }
306	
307	    int num_empty = state_after_tilt.count_empty_cells();
308	    if (num_empty == 0) {
309	        return state_after_tilt.evaluate();
310	    }
311	
312	    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
313	    int sample_count = (depth_remaining == 2) ? samples_d1 : samples_d2;
314	    int actual_num_samples = std::min(sample_count, num_empty);
315	
316	    if (actual_num_samples == 0) {
317	        return state_after_tilt.evaluate();
318	    }
319	
320	    double sum_over_sampled_placements = 0.0;
321	    for (int s = 0; s < actual_num_samples; ++s) {
322	        int p_val_1_indexed_sample;
323	        if (actual_num_samples == num_empty) {
324	            p_val_1_indexed_sample = s + 1;
325	        } else {
326	            p_val_1_indexed_sample = rng.uniform_int(1, num_empty);
327	        }
328	
329	        GameState S_after_placement = state_after_tilt;
330	        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val_1_indexed_sample);
331	        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
332	        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;
333	
334	        double max_eval_for_this_placement = std::numeric_limits<double>::lowest();
335	        for (int dir_idx_next_tilt = 0; dir_idx_next_tilt < NUM_DIRECTIONS; ++dir_idx_next_tilt) {
336	            GameState S_after_next_tilt = S_after_placement;
337	            S_after_next_tilt.apply_tilt(dir_idx_next_tilt);
338	            double val = eval_lookahead(S_after_next_tilt, S_after_placement.turn_num_1_indexed,
339	                                        depth_remaining - 1, samples_d1, samples_d2);
340	            if (val > max_eval_for_this_placement) {
341	                max_eval_for_this_placement = val;
342	            }
343	        }
344	        sum_over_sampled_placements += max_eval_for_this_placement;
345	    }
346	
347	    return sum_over_sampled_placements / actual_num_samples;
348	}
