                    bbs[fl].max_r = std::max(bbs[fl].max_r, r);
                    bbs[fl].min_c = std::min(bbs[fl].min_c, c);
                    bbs[fl].max_c = std::max(bbs[fl].max_c, c);
                    bbs[fl].count++;
                }
            }
        }
