double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed,
                      int depth_remaining, int samples_d1, int samples_d2) {
    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
        return state_after_tilt.evaluate();
    }

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) {
        return state_after_tilt.evaluate();
    }

    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
    int sample_count = (depth_remaining == 2) ? samples_d1 : samples_d2;
    int actual_num_samples = std::min(sample_count, num_empty);

    if (actual_num_samples == 0) {
        return state_after_tilt.evaluate();
    }

    double sum_over_sampled_placements = 0.0;
    for (int s = 0; s < actual_num_samples; ++s) {
        int p_val_1_indexed_sample;
        if (actual_num_samples == num_empty) {
            p_val_1_indexed_sample = s + 1;
        } else {
            p_val_1_indexed_sample = rng.uniform_int(1, num_empty);
        }

        GameState S_after_placement = state_after_tilt;
        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val_1_indexed_sample);
        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;

        double max_eval_for_this_placement = std::numeric_limits<double>::lowest();
        for (int dir_idx_next_tilt = 0; dir_idx_next_tilt < NUM_DIRECTIONS; ++dir_idx_next_tilt) {
            GameState S_after_next_tilt = S_after_placement;
            S_after_next_tilt.apply_tilt(dir_idx_next_tilt);
            double val = eval_lookahead(S_after_next_tilt, S_after_placement.turn_num_1_indexed,
                                        depth_remaining - 1, samples_d1, samples_d2);
            if (val > max_eval_for_this_placement) {
                max_eval_for_this_placement = val;
            }
        }
        sum_over_sampled_placements += max_eval_for_this_placement;
    }

    return sum_over_sampled_placements / actual_num_samples;
}

// Quick depth-1 evaluation for pruning
double eval_quick_d1(const GameState& state_after_tilt, int turn_T, int num_samples) {
    if (turn_T == NUM_TURNS) return state_after_tilt.evaluate_quick();

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) return state_after_tilt.evaluate_quick();

    int next_flavor = G_FLAVOR_SEQUENCE[turn_T];
    int actual_samples = std::min(num_samples, num_empty);
    if (actual_samples == 0) return state_after_tilt.evaluate_quick();

    double sum = 0.0;
    for (int s = 0; s < actual_samples; ++s) {
        int p = (actual_samples == num_empty) ? s + 1 : rng.uniform_int(1, num_empty);

        GameState gs = state_after_tilt;
        auto loc = gs.find_pth_empty_cell(p);
        gs.place_candy(loc.first, loc.second, next_flavor);
        gs.turn_num_1_indexed = turn_T + 1;

        double best = std::numeric_limits<double>::lowest();
        for (int d = 0; d < NUM_DIRECTIONS; ++d) {
            GameState gs2 = gs;
            gs2.apply_tilt(d);
            double v = gs2.evaluate_quick();
            if (v > best) best = v;
        }
        sum += best;
    }
    return sum / actual_samples;
}

char decide_tilt_direction(const GameState& current_gs_after_placement) {
    double time_used = elapsed_ms();
    double time_remaining = 1900.0 - time_used;
    int turns_remaining = NUM_TURNS - current_gs_after_placement.turn_num_1_indexed + 1;
    double budget_per_turn = time_remaining / turns_remaining;

    int turn = current_gs_after_placement.turn_num_1_indexed;

    int samples_d1, samples_d2;
    bool do_pruning = false;

    if (budget_per_turn < 8.0) {
        samples_d1 = 5;
        samples_d2 = 3;
    } else if (budget_per_turn < 14.0) {
        samples_d1 = 8;
        samples_d2 = 3;
    } else if (turn < 20) {
        samples_d1 = 30;
        samples_d2 = 9;
        do_pruning = true;
    } else if (turn < 50) {
        samples_d1 = 25;
        samples_d2 = 8;
        do_pruning = true;
    } else if (turn < 80) {
        samples_d1 = 20;
        samples_d2 = 7;
        do_pruning = true;
    } else {
        samples_d1 = 14;
        samples_d2 = 5;
    }

    // Determine which directions to fully evaluate
    std::array<bool, 4> evaluate_dir = {true, true, true, true};
    int dirs_to_eval = 4;

    if (do_pruning && budget_per_turn > 18.0) {
        // Quick depth-1 pass to prune worst direction
        std::array<double, 4> quick_scores;
        int prune_samples = std::min(12, current_gs_after_placement.count_empty_cells());

        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
            GameState gs = current_gs_after_placement;
            gs.apply_tilt(i);
            quick_scores[i] = eval_quick_d1(gs, current_gs_after_placement.turn_num_1_indexed, prune_samples);
        }

        // Find the worst direction and prune it
        int worst = 0;
        for (int i = 1; i < 4; ++i) {
            if (quick_scores[i] < quick_scores[worst]) worst = i;
        }

        // Only prune if the worst is significantly worse than the best
        double best_quick = *std::max_element(quick_scores.begin(), quick_scores.end());
        double worst_quick = quick_scores[worst];
        if (best_quick > worst_quick * 1.001 + 1.0) {
            evaluate_dir[worst] = false;
            dirs_to_eval = 3;
            // Boost samples since we evaluate fewer directions
            samples_d1 = samples_d1 * 4 / 3;
            samples_d2 = samples_d2 * 4 / 3;
        }
    }

    // Full depth-2 evaluation on remaining directions
    double best_eval = std::numeric_limits<double>::lowest();
    int best_dir = 0;

    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        if (!evaluate_dir[i]) continue;

        GameState gs_after_tilt = current_gs_after_placement;
        gs_after_tilt.apply_tilt(i);

        double eval;
        if (budget_per_turn < 14.0) {
            // Depth-1 mode
            eval = eval_lookahead(gs_after_tilt, current_gs_after_placement.turn_num_1_indexed,
                                   1, samples_d1, samples_d2);
        } else {
            eval = eval_lookahead(gs_after_tilt, current_gs_after_placement.turn_num_1_indexed,
                                   2, samples_d1, samples_d2);
        }

        if (eval > best_eval) {
            best_eval = eval;
            best_dir = i;
        }
    }

    return DIR_CHARS[best_dir];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

