                        return {r_idx, c_idx};
                    }
                }
            }
        }
        return {-1, -1};
    }

    int count_empty_cells() const {
        return GRID_SIZE * GRID_SIZE - num_candies;
    }

    void apply_tilt(int dir_idx) {
        if (dir_idx == 0) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = 0;
                for (int r = 0; r < GRID_SIZE; ++r) {
                    if (board[r][c] != 0) {
                        if (r != write_r) {
                            board[write_r][c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_r++;
                    }
                }
            }
        } else if (dir_idx == 1) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r) {
                    if (board[r][c] != 0) {
                        if (r != write_r) {
                            board[write_r][c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_r--;
                    }
                }
            }
        } else if (dir_idx == 2) {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = 0;
                for (int c = 0; c < GRID_SIZE; ++c) {
                    if (board[r][c] != 0) {
                        if (c != write_c) {
                            board[r][write_c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_c++;
                    }
                }
            }
        } else {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    if (board[r][c] != 0) {
                        if (c != write_c) {
                            board[r][write_c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_c--;
                    }
                }
            }
        }
    }

    long long calculate_sum_sq_comp_size() const {
        long long total_sq_sum = 0;
        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);

        std::array<std::pair<int, int>, GRID_SIZE * GRID_SIZE> q_arr;

        for (int r_start = 0; r_start < GRID_SIZE; ++r_start) {
            for (int c_start = 0; c_start < GRID_SIZE; ++c_start) {
                if (board[r_start][c_start] != 0 && !visited[r_start][c_start]) {
                    int current_flavor = board[r_start][c_start];
                    long long current_comp_size = 0;

                    q_arr[0] = {r_start, c_start};
                    visited[r_start][c_start] = true;
                    int head = 0;
                    int tail = 1;

                    while(head < tail){
                        current_comp_size++;
                        int curr_r = q_arr[head].first;
                        int curr_c = q_arr[head].second;
                        head++;

                        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
                            int nr = curr_r + DR[i];
                            int nc = curr_c + DC[i];
                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                !visited[nr][nc] && board[nr][nc] == current_flavor) {
                                visited[nr][nc] = true;
                                q_arr[tail++] = {nr, nc};
                            }
                        }
                    }
                    total_sq_sum += current_comp_size * current_comp_size;
                }
            }
        }
        return total_sq_sum;
    }

    int count_same_flavor_adjacencies() const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) continue;
                int fl = board[r][c];
                if (r + 1 < GRID_SIZE && board[r+1][c] == fl) count++;
                if (c + 1 < GRID_SIZE && board[r][c+1] == fl) count++;
            }
        }
        return count;
    }

    // Merge potential: count pairs of same-flavor components separated by gap=1
    // (one tilt could merge them). Weighted by product of sizes.
    double merge_potential() const {
        // Find connected components and their sizes
        std::array<std::array<int, GRID_SIZE>, GRID_SIZE> comp_id;
        for (int i = 0; i < GRID_SIZE; ++i) comp_id[i].fill(-1);

        std::array<int, GRID_SIZE * GRID_SIZE> comp_sizes;
        std::array<int, GRID_SIZE * GRID_SIZE> comp_flavors;
        int num_comps = 0;

        std::array<std::pair<int, int>, GRID_SIZE * GRID_SIZE> q_arr;

        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0 && comp_id[r][c] == -1) {
                    int cid = num_comps++;
                    int flavor = board[r][c];
                    comp_flavors[cid] = flavor;
                    int size = 0;

                    q_arr[0] = {r, c};
                    comp_id[r][c] = cid;
                    int head = 0, tail = 1;

                    while (head < tail) {
                        size++;
                        int cr = q_arr[head].first;
                        int cc = q_arr[head].second;
                        head++;
                        for (int d = 0; d < 4; ++d) {
                            int nr = cr + DR[d], nc = cc + DC[d];
                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                comp_id[nr][nc] == -1 && board[nr][nc] == flavor) {
                                comp_id[nr][nc] = cid;
                                q_arr[tail++] = {nr, nc};
                            }
                        }
                    }
                    comp_sizes[cid] = size;
                }
            }
        }

        // For each pair of adjacent same-flavor components (gap=0, already connected edges)
        // We want "near-merge" pairs: same flavor components with cells 2 apart
        // (separated by exactly one cell, which may be empty or different flavor)
        // Use a set to avoid counting pairs multiple times
        double score = 0.0;
        std::array<std::array<bool, 100>, 100> seen_pairs;
        // Only need num_comps x num_comps, use flat check
        // Actually just iterate cells and check gap-2 neighbors
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) continue;
                int cid1 = comp_id[r][c];
                // Check cells at distance 2 (skip one)
                for (int d = 0; d < 4; ++d) {
                    int mr = r + DR[d], mc = c + DC[d];
                    int nr = r + 2*DR[d], nc = c + 2*DC[d];
                    if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE) {
                        if (board[nr][nc] == board[r][c]) {
                            int cid2 = comp_id[nr][nc];
                            if (cid1 != cid2) {
                                // Near-merge pair found
                                int s1 = comp_sizes[cid1], s2 = comp_sizes[cid2];
                                // Merging would change score from s1^2+s2^2 to (s1+s2)^2
                                // Gain = 2*s1*s2
                                score += 2.0 * s1 * s2;
                            }
                        }
                    }
                }
            }
        }
        return score;
    }

    double evaluate() const {
        long long sum_sq_comp = calculate_sum_sq_comp_size();
        int adj_count = count_same_flavor_adjacencies();

        double progress = static_cast<double>(turn_num_1_indexed) / NUM_TURNS;

        // Bounding box tightness
        struct FlavorBB {
            int min_r = GRID_SIZE, max_r = -1, min_c = GRID_SIZE, max_c = -1;
            int count = 0;
        };
        std::array<FlavorBB, NUM_FLAVORS + 1> bbs;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0) {
                    int fl = board[r][c];
                    bbs[fl].min_r = std::min(bbs[fl].min_r, r);
                    bbs[fl].max_r = std::max(bbs[fl].max_r, r);
                    bbs[fl].min_c = std::min(bbs[fl].min_c, c);
                    bbs[fl].max_c = std::max(bbs[fl].max_c, c);
                    bbs[fl].count++;
                }
            }
        }
        double bb_score = 0.0;
        for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
            if (bbs[fl].count == 0) continue;
            int bb_area = (bbs[fl].max_r - bbs[fl].min_r + 1) * (bbs[fl].max_c - bbs[fl].min_c + 1);
            bb_score -= (double)(bb_area - bbs[fl].count) * bbs[fl].count;
        }

        // Row/column purity
        double rc_score = 0.0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            std::array<int, NUM_FLAVORS + 1> cnt{};
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0) cnt[board[r][c]]++;
            }
            int max_cnt = *std::max_element(cnt.begin() + 1, cnt.end());
            rc_score += max_cnt * max_cnt;
        }
        for (int c = 0; c < GRID_SIZE; ++c) {
            std::array<int, NUM_FLAVORS + 1> cnt{};
            for (int r = 0; r < GRID_SIZE; ++r) {
                if (board[r][c] != 0) cnt[board[r][c]]++;
            }
            int max_cnt = *std::max_element(cnt.begin() + 1, cnt.end());
            rc_score += max_cnt * max_cnt;
        }

        double conn_weight = 25.0 + 75.0 * progress;
        double adj_weight = 35.0;
        double bb_weight = 3.0 * (1.0 - progress * 0.3);
        double rc_weight = 2.0 * (1.0 - progress * 0.5);

        return conn_weight * sum_sq_comp + adj_weight * adj_count
             + bb_weight * bb_score + rc_weight * rc_score;
    }

    // Lightweight eval for pruning pass
    double evaluate_quick() const {
        int adj_count = count_same_flavor_adjacencies();
        long long sum_sq_comp = calculate_sum_sq_comp_size();

        double progress = static_cast<double>(turn_num_1_indexed) / NUM_TURNS;
        double conn_weight = 25.0 + 75.0 * progress;
        double adj_weight = 35.0;

        return conn_weight * sum_sq_comp + adj_weight * adj_count;
    }
};

double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed,
                      int depth_remaining, int samples_d1, int samples_d2) {
    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
        return state_after_tilt.evaluate();
    }

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) {
        return state_after_tilt.evaluate();
    }

    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
    int sample_count = (depth_remaining == 2) ? samples_d1 : samples_d2;
    int actual_num_samples = std::min(sample_count, num_empty);

    if (actual_num_samples == 0) {
        return state_after_tilt.evaluate();
    }

    double sum_over_sampled_placements = 0.0;
    for (int s = 0; s < actual_num_samples; ++s) {
        int p_val_1_indexed_sample;
        if (actual_num_samples == num_empty) {
            p_val_1_indexed_sample = s + 1;
        } else {
            p_val_1_indexed_sample = rng.uniform_int(1, num_empty);
        }

        GameState S_after_placement = state_after_tilt;
        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val_1_indexed_sample);
        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;

        double max_eval_for_this_placement = std::numeric_limits<double>::lowest();
        for (int dir_idx_next_tilt = 0; dir_idx_next_tilt < NUM_DIRECTIONS; ++dir_idx_next_tilt) {
            GameState S_after_next_tilt = S_after_placement;
            S_after_next_tilt.apply_tilt(dir_idx_next_tilt);
            double val = eval_lookahead(S_after_next_tilt, S_after_placement.turn_num_1_indexed,
                                        depth_remaining - 1, samples_d1, samples_d2);
            if (val > max_eval_for_this_placement) {
                max_eval_for_this_placement = val;
            }
        }
        sum_over_sampled_placements += max_eval_for_this_placement;
    }

    return sum_over_sampled_placements / actual_num_samples;
}

// Quick depth-1 evaluation for pruning
double eval_quick_d1(const GameState& state_after_tilt, int turn_T, int num_samples) {
    if (turn_T == NUM_TURNS) return state_after_tilt.evaluate_quick();

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) return state_after_tilt.evaluate_quick();

    int next_flavor = G_FLAVOR_SEQUENCE[turn_T];
    int actual_samples = std::min(num_samples, num_empty);
    if (actual_samples == 0) return state_after_tilt.evaluate_quick();

    double sum = 0.0;
    for (int s = 0; s < actual_samples; ++s) {
        int p = (actual_samples == num_empty) ? s + 1 : rng.uniform_int(1, num_empty);

        GameState gs = state_after_tilt;
        auto loc = gs.find_pth_empty_cell(p);
        gs.place_candy(loc.first, loc.second, next_flavor);
        gs.turn_num_1_indexed = turn_T + 1;

        double best = std::numeric_limits<double>::lowest();
        for (int d = 0; d < NUM_DIRECTIONS; ++d) {
            GameState gs2 = gs;
            gs2.apply_tilt(d);
            double v = gs2.evaluate_quick();
            if (v > best) best = v;
        }
        sum += best;
    }
    return sum / actual_samples;
}

char decide_tilt_direction(const GameState& current_gs_after_placement) {
    double time_used = elapsed_ms();
    double time_remaining = 1900.0 - time_used;
    int turns_remaining = NUM_TURNS - current_gs_after_placement.turn_num_1_indexed + 1;
    double budget_per_turn = time_remaining / turns_remaining;

    int turn = current_gs_after_placement.turn_num_1_indexed;

    int samples_d1, samples_d2;
    bool do_pruning = false;

    if (budget_per_turn < 8.0) {
        samples_d1 = 5;
        samples_d2 = 3;
    } else if (budget_per_turn < 14.0) {
        samples_d1 = 8;
        samples_d2 = 3;
    } else if (turn < 20) {
        samples_d1 = 30;
        samples_d2 = 9;
        do_pruning = true;
    } else if (turn < 50) {
        samples_d1 = 25;
        samples_d2 = 8;
        do_pruning = true;
    } else if (turn < 80) {
        samples_d1 = 20;
        samples_d2 = 7;
        do_pruning = true;
    } else {
        samples_d1 = 14;
        samples_d2 = 5;
    }

    // Determine which directions to fully evaluate
    std::array<bool, 4> evaluate_dir = {true, true, true, true};
    int dirs_to_eval = 4;

    if (do_pruning && budget_per_turn > 18.0) {
        // Quick depth-1 pass to prune worst direction
        std::array<double, 4> quick_scores;
        int prune_samples = std::min(12, current_gs_after_placement.count_empty_cells());

        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
            GameState gs = current_gs_after_placement;
            gs.apply_tilt(i);
            quick_scores[i] = eval_quick_d1(gs, current_gs_after_placement.turn_num_1_indexed, prune_samples);
        }

        // Find the worst direction and prune it
        int worst = 0;
        for (int i = 1; i < 4; ++i) {
            if (quick_scores[i] < quick_scores[worst]) worst = i;
        }

        // Only prune if the worst is significantly worse than the best
        double best_quick = *std::max_element(quick_scores.begin(), quick_scores.end());
        double worst_quick = quick_scores[worst];
        if (best_quick > worst_quick * 1.001 + 1.0) {
            evaluate_dir[worst] = false;
            dirs_to_eval = 3;
            // Boost samples since we evaluate fewer directions
            samples_d1 = samples_d1 * 4 / 3;
            samples_d2 = samples_d2 * 4 / 3;
        }
    }

    // Full depth-2 evaluation on remaining directions
    double best_eval = std::numeric_limits<double>::lowest();
    int best_dir = 0;

    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        if (!evaluate_dir[i]) continue;

        GameState gs_after_tilt = current_gs_after_placement;
        gs_after_tilt.apply_tilt(i);

        double eval;
        if (budget_per_turn < 14.0) {
            // Depth-1 mode
            eval = eval_lookahead(gs_after_tilt, current_gs_after_placement.turn_num_1_indexed,
                                   1, samples_d1, samples_d2);
        } else {
            eval = eval_lookahead(gs_after_tilt, current_gs_after_placement.turn_num_1_indexed,
                                   2, samples_d1, samples_d2);
        }

        if (eval > best_eval) {
            best_eval = eval;
            best_dir = i;
        }
    }

    return DIR_CHARS[best_dir];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    program_start_time = std::chrono::steady_clock::now();

    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
    }

    GameState current_gs;

    for (int t_0_indexed = 0; t_0_indexed < NUM_TURNS; ++t_0_indexed) {
        current_gs.turn_num_1_indexed = t_0_indexed + 1;

        int p_val_1_indexed;
        std::cin >> p_val_1_indexed;

        std::pair<int, int> candy_loc = current_gs.find_pth_empty_cell(p_val_1_indexed);
        current_gs.place_candy(candy_loc.first, candy_loc.second, G_FLAVOR_SEQUENCE[t_0_indexed]);

        char chosen_dir_char = decide_tilt_direction(current_gs);

        std::cout << chosen_dir_char << std::endl;

        int dir_idx_to_apply = 0;
        for(int k=0; k<NUM_DIRECTIONS; ++k) {
            if(DIR_CHARS[k] == chosen_dir_char) {
                dir_idx_to_apply = k;
                break;
            }
        }
        current_gs.apply_tilt(dir_idx_to_apply);
    }

    return 0;
}
