    // then finds the best tilt response, evaluating that at depth-1
    std::array<double, 4> total_score = {0.0, 0.0, 0.0, 0.0};
    int num_iterations = 0;

    // Determine depth-2 inner samples
    int inner_samples;
    if (turn_T < 30) inner_samples = 8;
    else if (turn_T < 60) inner_samples = 7;
    else if (turn_T < 85) inner_samples = 6;
