                if (turn_T + 1 >= NUM_TURNS || ne2 == 0) {
                    double v = gs_tilt2.evaluate();
                    if (v > best_inner) best_inner = v;
                    continue;
                }

                int next_flavor2 = G_FLAVOR_SEQUENCE[turn_T + 1];
                int actual_inner = std::min(inner_samples, ne2);
                double sum_inner = 0.0;

                for (int si = 0; si < actual_inner; ++si) {
                    int p2 = (actual_inner == ne2) ? si + 1 : rng.uniform_int(1, ne2);
                    GameState gs3 = gs_tilt2;
