const int GRID_SIZE = 10;
const int NUM_TURNS = 100;
const int NUM_FLAVORS = 3;

const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};
const int NUM_DIRECTIONS = 4;

std::array<int, NUM_TURNS> G_FLAVOR_SEQUENCE;

const int MAX_LOOKAHEAD_DEPTH = 2;

struct XorshiftRNG {
    uint64_t x;
    XorshiftRNG() : x(std::chrono::steady_clock::now().time_since_epoch().count()) {}

    uint64_t next() {
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        return x;
    }

    int uniform_int(int min_val, int max_val) {
        if (min_val > max_val) return min_val;
        if (min_val == max_val) return min_val;
        uint64_t range = static_cast<uint64_t>(max_val) - min_val + 1;
        return min_val + static_cast<int>(next() % range);
    }
};
XorshiftRNG rng;

auto program_start_time = std::chrono::steady_clock::now();

double elapsed_ms() {
    auto now = std::chrono::steady_clock::now();
    return std::chrono::duration<double, std::milli>(now - program_start_time).count();
}

struct GameState {
    std::array<std::array<int, GRID_SIZE>, GRID_SIZE> board;
    int num_candies;
    int turn_num_1_indexed;

    GameState() : num_candies(0), turn_num_1_indexed(0) {
        for (int i = 0; i < GRID_SIZE; ++i) {
            board[i].fill(0);
        }
    }

    void place_candy(int r, int c, int flavor) {
        board[r][c] = flavor;
        num_candies++;
    }

    std::pair<int, int> find_pth_empty_cell(int p_1_indexed) const {
        int count = 0;
        for (int r_idx = 0; r_idx < GRID_SIZE; ++r_idx) {
            for (int c_idx = 0; c_idx < GRID_SIZE; ++c_idx) {
                if (board[r_idx][c_idx] == 0) {
                    count++;
                    if (count == p_1_indexed) {
                        return {r_idx, c_idx};
                    }
                }
            }
        }
        return {-1, -1};
    }

    int count_empty_cells() const {
        return GRID_SIZE * GRID_SIZE - num_candies;
    }

    void apply_tilt(int dir_idx) {
        if (dir_idx == 0) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = 0;
                for (int r = 0; r < GRID_SIZE; ++r) {
                    if (board[r][c] != 0) {
                        if (r != write_r) {
                            board[write_r][c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_r++;
                    }
                }
            }
        } else if (dir_idx == 1) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r) {
                    if (board[r][c] != 0) {
                        if (r != write_r) {
                            board[write_r][c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_r--;
                    }
                }
            }
        } else if (dir_idx == 2) {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = 0;
                for (int c = 0; c < GRID_SIZE; ++c) {
                    if (board[r][c] != 0) {
                        if (c != write_c) {
                            board[r][write_c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_c++;
                    }
                }
            }
        } else {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    if (board[r][c] != 0) {
                        if (c != write_c) {
                            board[r][write_c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_c--;
                    }
                }
            }
        }
    }

    long long calculate_sum_sq_comp_size() const {
        long long total_sq_sum = 0;
        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);

        std::array<std::pair<int, int>, GRID_SIZE * GRID_SIZE> q_arr;

        for (int r_start = 0; r_start < GRID_SIZE; ++r_start) {
            for (int c_start = 0; c_start < GRID_SIZE; ++c_start) {
                if (board[r_start][c_start] != 0 && !visited[r_start][c_start]) {
                    int current_flavor = board[r_start][c_start];
                    long long current_comp_size = 0;

                    q_arr[0] = {r_start, c_start};
                    visited[r_start][c_start] = true;
                    int head = 0;
                    int tail = 1;

                    while(head < tail){
                        current_comp_size++;
                        int curr_r = q_arr[head].first;
                        int curr_c = q_arr[head].second;
                        head++;

                        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
                            int nr = curr_r + DR[i];
                            int nc = curr_c + DC[i];
                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                !visited[nr][nc] && board[nr][nc] == current_flavor) {
                                visited[nr][nc] = true;
                                q_arr[tail++] = {nr, nc};
                            }
                        }
                    }
                    total_sq_sum += current_comp_size * current_comp_size;
                }
            }
        }
        return total_sq_sum;
    }

    int count_same_flavor_adjacencies() const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) continue;
                int fl = board[r][c];
                if (r + 1 < GRID_SIZE && board[r+1][c] == fl) count++;
                if (c + 1 < GRID_SIZE && board[r][c+1] == fl) count++;
            }
        }
        return count;
    }

    // Bounding box tightness: for each flavor, compute the ratio of
    // actual cells to bounding box area. Higher = more rectangular/compact.
    double bounding_box_tightness() const {
        struct FlavorBB {
            int min_r = GRID_SIZE, max_r = -1, min_c = GRID_SIZE, max_c = -1;
            int count = 0;
        };
        std::array<FlavorBB, NUM_FLAVORS + 1> bbs;

        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0) {
                    int fl = board[r][c];
                    bbs[fl].min_r = std::min(bbs[fl].min_r, r);
                    bbs[fl].max_r = std::max(bbs[fl].max_r, r);
                    bbs[fl].min_c = std::min(bbs[fl].min_c, c);
                    bbs[fl].max_c = std::max(bbs[fl].max_c, c);
                    bbs[fl].count++;
                }
            }
        }

        double score = 0.0;
        for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
            if (bbs[fl].count == 0) continue;
            int bb_area = (bbs[fl].max_r - bbs[fl].min_r + 1) * (bbs[fl].max_c - bbs[fl].min_c + 1);
            // Negative penalty: larger bb_area relative to count is bad
            // We want count / bb_area to be high (close to 1)
            // Penalty = bb_area - count (lower is better, so negate)
            score -= (double)(bb_area - bbs[fl].count) * bbs[fl].count;
        }
        return score;
    }

    // "Row/column purity": for each row and column, how many cells belong to the dominant flavor
    double row_col_purity() const {
        double score = 0.0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            std::array<int, NUM_FLAVORS + 1> cnt{};
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0) cnt[board[r][c]]++;
            }
            int max_cnt = *std::max_element(cnt.begin() + 1, cnt.end());
            score += max_cnt * max_cnt;
        }
        for (int c = 0; c < GRID_SIZE; ++c) {
            std::array<int, NUM_FLAVORS + 1> cnt{};
            for (int r = 0; r < GRID_SIZE; ++r) {
                if (board[r][c] != 0) cnt[board[r][c]]++;
            }
            int max_cnt = *std::max_element(cnt.begin() + 1, cnt.end());
            score += max_cnt * max_cnt;
        }
        return score;
    }

    double evaluate() const {
        long long sum_sq_comp = calculate_sum_sq_comp_size();
        int adj_count = count_same_flavor_adjacencies();
        double bb_tight = bounding_box_tightness();
        double rc_purity = row_col_purity();

        double progress = static_cast<double>(turn_num_1_indexed) / NUM_TURNS;

        // Connectivity: the actual objective, increasingly important
        double conn_weight = 25.0 + 75.0 * progress;
        // Adjacency: local proxy
        double adj_weight = 35.0;
        // Bounding box tightness: encourages compaction into small rectangles
        double bb_weight = 3.0 * (1.0 - progress * 0.3);
        // Row/column purity: encourages band-like flavor separation
        double rc_weight = 2.0 * (1.0 - progress * 0.5);

        return conn_weight * sum_sq_comp + adj_weight * adj_count
             + bb_weight * bb_tight + rc_weight * rc_purity;
    }
};

double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed,
                      int depth_remaining, int samples_d1, int samples_d2);

char decide_tilt_direction_logic(const GameState& current_gs_after_placement,
                                  int samples_d1, int samples_d2, int max_depth) {
    double best_overall_eval = std::numeric_limits<double>::lowest();
    int best_dir_idx = 0;

    int turn_T_for_lookahead_base = current_gs_after_placement.turn_num_1_indexed;

    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        GameState gs_after_tilt = current_gs_after_placement;
        gs_after_tilt.apply_tilt(i);

        double eval = eval_lookahead(gs_after_tilt, turn_T_for_lookahead_base,
                                     max_depth, samples_d1, samples_d2);

        if (eval > best_overall_eval) {
            best_overall_eval = eval;
            best_dir_idx = i;
        }
    }
    return DIR_CHARS[best_dir_idx];
}


double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed,
                      int depth_remaining, int samples_d1, int samples_d2) {
    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
        return state_after_tilt.evaluate();
    }

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) {
        return state_after_tilt.evaluate();
    }

    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
    int sample_count = (depth_remaining == 2) ? samples_d1 : samples_d2;
    int actual_num_samples = std::min(sample_count, num_empty);

    if (actual_num_samples == 0) {
        return state_after_tilt.evaluate();
    }

    double sum_over_sampled_placements = 0.0;
    for (int s = 0; s < actual_num_samples; ++s) {
        int p_val_1_indexed_sample;
        if (actual_num_samples == num_empty) {
            p_val_1_indexed_sample = s + 1;
        } else {
            p_val_1_indexed_sample = rng.uniform_int(1, num_empty);
        }

        GameState S_after_placement = state_after_tilt;
        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val_1_indexed_sample);
        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;

        double max_eval_for_this_placement = std::numeric_limits<double>::lowest();
        for (int dir_idx_next_tilt = 0; dir_idx_next_tilt < NUM_DIRECTIONS; ++dir_idx_next_tilt) {
            GameState S_after_next_tilt = S_after_placement;
            S_after_next_tilt.apply_tilt(dir_idx_next_tilt);
            double val = eval_lookahead(S_after_next_tilt, S_after_placement.turn_num_1_indexed,
                                        depth_remaining - 1, samples_d1, samples_d2);
            if (val > max_eval_for_this_placement) {
                max_eval_for_this_placement = val;
            }
        }
        sum_over_sampled_placements += max_eval_for_this_placement;
    }

    return sum_over_sampled_placements / actual_num_samples;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    program_start_time = std::chrono::steady_clock::now();

    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
    }

    GameState current_gs;

    const double TOTAL_TIME_BUDGET_MS = 1900.0;

    for (int t_0_indexed = 0; t_0_indexed < NUM_TURNS; ++t_0_indexed) {
        current_gs.turn_num_1_indexed = t_0_indexed + 1;

        int p_val_1_indexed;
        std::cin >> p_val_1_indexed;

        std::pair<int, int> candy_loc = current_gs.find_pth_empty_cell(p_val_1_indexed);
        current_gs.place_candy(candy_loc.first, candy_loc.second, G_FLAVOR_SEQUENCE[t_0_indexed]);

        double time_used = elapsed_ms();
        double time_remaining = TOTAL_TIME_BUDGET_MS - time_used;
        int turns_remaining = NUM_TURNS - t_0_indexed;
        double budget_per_turn = time_remaining / turns_remaining;

        int samples_d1, samples_d2, max_depth;

        if (t_0_indexed < 20) {
            max_depth = 2;
            samples_d1 = 30;
            samples_d2 = 9;
        } else if (t_0_indexed < 50) {
            max_depth = 2;
            samples_d1 = 25;
            samples_d2 = 8;
        } else if (t_0_indexed < 80) {
            max_depth = 2;
            samples_d1 = 20;
            samples_d2 = 7;
        } else {
            max_depth = 2;
            samples_d1 = 14;
            samples_d2 = 5;
        }

        if (budget_per_turn < 8.0) {
            max_depth = 1;
            samples_d1 = 5;
            samples_d2 = 3;
        } else if (budget_per_turn < 14.0) {
            samples_d1 = std::min(samples_d1, 8);
            samples_d2 = std::min(samples_d2, 3);
            max_depth = 1;
        }

        char chosen_dir_char = decide_tilt_direction_logic(current_gs, samples_d1, samples_d2, max_depth);

        std::cout << chosen_dir_char << std::endl;

        int dir_idx_to_apply = 0;
        for(int k=0; k<NUM_DIRECTIONS; ++k) {
            if(DIR_CHARS[k] == chosen_dir_char) {
                dir_idx_to_apply = k;
                break;
            }
        }
        current_gs.apply_tilt(dir_idx_to_apply);
    }

    return 0;
}
